#include <bits/stdc++.h>
using namespace std;
const int N=10005;
long long n,vis[N],cnt,val[N],ans;
struct node
{
    long long x,low,high,flag;//1:左边的线 -1:右边的线
    bool operator<(const node other) const
    {
        return x<other.x;
    }
} a[N];
struct Node
{
    long long len,flag;//len表示区间覆盖长度，flag表示区间是否被全覆盖
} tr[80005];
void pushup(int id,int l,int r)
{
    if(tr[id].flag)
    {
        tr[id].len=val[r+1]-val[l];
    }
    else tr[id].len=tr[id*2].len+tr[id*2+1].len;
}
void update(int id,int l,int r,int x,int y,int flag)
{
    if(x<=l&&r<=y)
    {
		tr[id].flag+=flag;
		pushup(id,l,r);
		return;	
	}
	int mid=(l+r)/2;
	if(x<=mid)
    {
		update(id*2,l,mid,x,y,flag);
	} 
	if(y>mid)
    {
		update(id*2+1,mid+1,r,x,y,flag);
	}
	pushup(id,l,r);
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int x,y,xx,yy;
        cin>>x>>y>>xx>>yy;
        vis[++cnt]=y;
        a[cnt].x=x;
        a[cnt].low=y;
        a[cnt].high=yy;
        a[cnt].flag=1;
        vis[++cnt]=yy;
        a[cnt].x=xx;
        a[cnt].low=y;
        a[cnt].high=yy;
        a[cnt].flag=-1;
    }
    sort(vis+1,vis+cnt+1);
    int len=unique(vis+1,vis+1+cnt)-vis-1;
    for(int i=1;i<=cnt;i++)
    {
        int pos1=lower_bound(vis+1,vis+1+len,a[i].high)-vis;
        int pos2=lower_bound(vis+1,vis+1+len,a[i].low)-vis;
        val[pos1]=a[i].high;
        val[pos2]=a[i].low;
        a[i].high=pos1;
        a[i].low=pos2;
    }
    sort(a+1,a+1+cnt);
    for(int i=1;i<cnt;i++)
    {
        update(1,1,cnt,a[i].low,a[i].high-1,a[i].flag);
        ans+=((a[i+1].x-a[i].x)*tr[1].len);
    }
    cout<<ans;
    return 0;
}
